import{_ as a,c as t,o as l,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Platform Features: CLI Commands & Skills | OpenSkills","description":"Learn OpenSkills CLI commands and skill management. Master installation sources, global vs project modes, listing, updating, and removing skills.","frontmatter":{"title":"Platform Features: CLI Commands & Skills | OpenSkills","sidebarTitle":"Platform Features","subtitle":"Platform Features: CLI Commands & Skill Management","description":"Learn OpenSkills CLI commands and skill management. Master installation sources, global vs project modes, listing, updating, and removing skills.","order":2},"headers":[],"relativePath":"numman-ali/openskills/platforms/index.md","filePath":"numman-ali/openskills/platforms/index.md"}'),o={name:"numman-ali/openskills/platforms/index.md"};function i(n,e,r,d,c,h){return l(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="platform-features" tabindex="-1">Platform Features <a class="header-anchor" href="#platform-features" aria-label="Permalink to &quot;Platform Features&quot;">​</a></h1><p>This section provides an in-depth explanation of the OpenSkills CLI&#39;s core commands and skill management features, helping you progress from &quot;using&quot; to &quot;mastering&quot; the tool.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Before You Begin</p><p>Before studying this section, please ensure you have completed the <a href="./../start/">Getting Started</a> section, especially:</p><ul><li><a href="./../start/installation/">Install OpenSkills</a>: Successfully installed OpenSkills CLI</li><li><a href="./../start/first-skill/">Install Your First Skill</a>: Understand the basic skill installation process</li></ul></div><h2 id="this-section" tabindex="-1">This Section <a class="header-anchor" href="#this-section" aria-label="Permalink to &quot;This Section&quot;">​</a></h2><p>This section covers 6 topics covering all core features of OpenSkills:</p><h3 id="command-reference" tabindex="-1"><a href="./cli-commands/">Command Reference</a> <a class="header-anchor" href="#command-reference" aria-label="Permalink to &quot;[Command Reference](./cli-commands/)&quot;">​</a></h3><p>Complete introduction to all 7 commands, parameters, and flags, with a command quick reference table. Suitable for users who need to quickly look up command usage.</p><h3 id="installation-sources" tabindex="-1"><a href="./install-sources/">Installation Sources</a> <a class="header-anchor" href="#installation-sources" aria-label="Permalink to &quot;[Installation Sources](./install-sources/)&quot;">​</a></h3><p>Detailed explanation of three installation sources: GitHub repositories, local paths, and private Git repositories. Use cases, command formats, and considerations for each method.</p><h3 id="global-installation-vs-project-local-installation" tabindex="-1"><a href="./global-vs-project/">Global Installation vs Project-Local Installation</a> <a class="header-anchor" href="#global-installation-vs-project-local-installation" aria-label="Permalink to &quot;[Global Installation vs Project-Local Installation](./global-vs-project/)&quot;">​</a></h3><p>Explains the difference between <code>--global</code> and default (project-local) installation, helping you choose the appropriate installation location and understand skill search priority rules.</p><h3 id="list-installed-skills" tabindex="-1"><a href="./list-skills/">List Installed Skills</a> <a class="header-anchor" href="#list-installed-skills" aria-label="Permalink to &quot;[List Installed Skills](./list-skills/)&quot;">​</a></h3><p>Teaches you how to use the <code>list</code> command to view installed skills and understand the meaning of <code>(project)</code> and <code>(global)</code> location tags.</p><h3 id="update-skills" tabindex="-1"><a href="./update-skills/">Update Skills</a> <a class="header-anchor" href="#update-skills" aria-label="Permalink to &quot;[Update Skills](./update-skills/)&quot;">​</a></h3><p>Guides you through using the <code>update</code> command to refresh installed skills, supporting both full updates and specific skill updates to keep skills synchronized with the source repository.</p><h3 id="remove-skills" tabindex="-1"><a href="./remove-skills/">Remove Skills</a> <a class="header-anchor" href="#remove-skills" aria-label="Permalink to &quot;[Remove Skills](./remove-skills/)&quot;">​</a></h3><p>Introduces two removal methods: the interactive <code>manage</code> command and the scripted <code>remove</code> command, helping you efficiently manage your skill library.</p><h2 id="learning-paths" tabindex="-1">Learning Paths <a class="header-anchor" href="#learning-paths" aria-label="Permalink to &quot;Learning Paths&quot;">​</a></h2><p>Choose the appropriate learning path based on your needs:</p><h3 id="path-a-systematic-learning-recommended-for-beginners" tabindex="-1">Path A: Systematic Learning (Recommended for Beginners) <a class="header-anchor" href="#path-a-systematic-learning-recommended-for-beginners" aria-label="Permalink to &quot;Path A: Systematic Learning (Recommended for Beginners)&quot;">​</a></h3><p>Study all content in order to build a complete knowledge system:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Command Reference → Installation Sources → Global vs Project → List Skills → Update Skills → Remove Skills</span></span></code></pre></div><h3 id="path-b-look-up-as-needed" tabindex="-1">Path B: Look Up as Needed <a class="header-anchor" href="#path-b-look-up-as-needed" aria-label="Permalink to &quot;Path B: Look Up as Needed&quot;">​</a></h3><p>Jump directly based on your current task:</p><table tabindex="0"><thead><tr><th>What You Want to Do</th><th>Read This</th></tr></thead><tbody><tr><td>Find usage for a specific command</td><td><a href="./cli-commands/">Command Reference</a></td></tr><tr><td>Install skills from a private repository</td><td><a href="./install-sources/">Installation Sources</a></td></tr><tr><td>Decide whether to install globally or locally</td><td><a href="./global-vs-project/">Global vs Project</a></td></tr><tr><td>View installed skills</td><td><a href="./list-skills/">List Installed Skills</a></td></tr><tr><td>Update skills to the latest version</td><td><a href="./update-skills/">Update Skills</a></td></tr><tr><td>Clean up unused skills</td><td><a href="./remove-skills/">Remove Skills</a></td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this section, you have mastered the daily use of OpenSkills. You can continue to:</p><ul><li><strong><a href="./../advanced/">Advanced Features</a></strong>: Learn about Universal mode, custom output paths, symbolic links, creating custom skills, and other advanced features</li><li><strong><a href="./../faq/">FAQ</a></strong>: Consult the FAQ and troubleshooting guide when you encounter problems</li></ul>',29)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
